  1→package protocol
  2→
  3→import (
  4→	"bufio"
  5→	"context"
  6→	"encoding/json"
  7→	"fmt"
  8→	"io"
  9→	"log/slog"
 10→	"os"
 11→	"strings"
 12→
 13→	"github.com/shatter-dev/shatter/shatter-go/generators"
 14→	"github.com/shatter-dev/shatter/shatter-go/instrument"
 15→	"github.com/shatter-dev/shatter/shatter-go/setup"
 16→)
 17→
 18→const frontendVersion = "0.1.0"
 19→const frontendLanguage = "go"
 20→
 21→// Handler processes protocol requests and writes responses.
 22→type Handler struct {
 23→	reader           *bufio.Scanner
 24→	writer           io.Writer
 25→	log              *slog.Logger
 26→	lastAnalyzedFile string // remembered from the most recent analyze command
 27→	registry         *generators.Registry
 28→	setupLoader      *setup.Loader
 29→}
 30→
 31→// NewHandler creates a handler reading from r, writing responses to w,
 32→// and logging to logw at the level set by SHATTER_LOG_LEVEL.
 33→func NewHandler(r io.Reader, w io.Writer, logw io.Writer) *Handler {
 34→	scanner := bufio.NewScanner(r)
 35→	scanner.Buffer(make([]byte, 0, 1024*1024), 10*1024*1024) // 10MB max line
 36→	return &Handler{
 37→		reader:      scanner,
 38→		writer:      w,
 39→		log:         slog.New(newPrefixHandler(logw, slogLevelFromEnv())),
 40→		registry:    generators.NewRegistry(),
 41→		setupLoader: setup.NewLoader(),
 42→	}
 43→}
 44→
 45→// NewHandlerWithLogLevel creates a handler with an explicit log level (for testing).
 46→func NewHandlerWithLogLevel(r io.Reader, w io.Writer, logw io.Writer, level string) *Handler {
 47→	scanner := bufio.NewScanner(r)
 48→	scanner.Buffer(make([]byte, 0, 1024*1024), 10*1024*1024)
 49→	return &Handler{
 50→		reader:      scanner,
 51→		writer:      w,
 52→		log:         slog.New(newPrefixHandler(logw, slogLevelFromString(level))),
 53→		registry:    generators.NewRegistry(),
 54→		setupLoader: setup.NewLoader(),
 55→	}
 56→}
 57→
 58→// Run processes requests until shutdown or EOF. Returns nil on clean shutdown.
 59→func (h *Handler) Run() error {
 60→	h.log.Debug("Starting Go frontend", "protocol", ProtocolVersion)
 61→
 62→	for h.reader.Scan() {
 63→		line := h.reader.Text()
 64→		if line == "" {
 65→			continue
 66→		}
 67→
 68→		h.log.Log(context.Background(), LevelTrace, "Received", "raw", line)
 69→
 70→		var req Request
 71→		if err := json.Unmarshal([]byte(line), &req); err != nil {
 72→			h.log.Log(context.Background(), LevelTrace, "Failed to parse request", "err", err)
 73→			errResp := Response{
 74→				ProtocolVersion: ProtocolVersion,
 75→				ID:              0,
 76→				Status:          "error",
 77→				Code:            ErrInvalidRequest,
 78→				Message:         fmt.Sprintf("Invalid JSON: %s", err.Error()),
 79→			}
 80→			if sendErr := h.send(errResp); sendErr != nil {
 81→				return fmt.Errorf("writing error response: %w", sendErr)
 82→			}
 83→			continue
 84→		}
 85→
 86→		resp, shutdown := h.dispatch(req)
 87→		if err := h.send(resp); err != nil {
 88→			return fmt.Errorf("writing response: %w", err)
 89→		}
 90→
 91→		if shutdown {
 92→			h.log.Debug("Shutting down")
 93→			return nil
 94→		}
 95→	}
 96→
 97→	if err := h.reader.Err(); err != nil {
 98→		return fmt.Errorf("reading stdin: %w", err)
 99→	}
100→
101→	h.log.Debug("Stdin closed, exiting")
102→	return nil
103→}
104→
105→func (h *Handler) dispatch(req Request) (Response, bool) {
106→	base := Response{
107→		ProtocolVersion: ProtocolVersion,
108→		ID:              req.ID,
109→	}
110→
111→	if req.ProtocolVersion != ProtocolVersion {
112→		base.Status = "error"
113→		base.Code = ErrVersionMismatch
114→		base.Message = fmt.Sprintf(
115→			"unsupported protocol version %q, expected %q",
116→			req.ProtocolVersion, ProtocolVersion,
117→		)
118→		return base, false
119→	}
120→
121→	switch req.Command {
122→	case "handshake":
123→		return h.handleHandshake(base, req), false
124→	case "analyze":
125→		return h.handleAnalyze(base, req), false
126→	case "instrument":
127→		return h.handleInstrument(base, req), false
128→	case "execute":
129→		return h.handleExecute(base, req), false
130→	case "setup":
131→		return h.handleSetup(base, req), false
132→	case "teardown":
133→		return h.handleTeardown(base, req), false
134→	case "generate":
135→		return h.handleGenerate(base, req), false
136→	case "shutdown":
137→		return h.handleShutdown(base), true
138→	default:
139→		base.Status = "error"
140→		base.Code = ErrInvalidRequest
141→		base.Message = fmt.Sprintf("unknown command: %s", req.Command)
142→		return base, false
143→	}
144→}
145→
146→func (h *Handler) handleHandshake(resp Response, req Request) Response {
147→	resp.Status = "handshake"
148→	resp.FrontendVersion = frontendVersion
149→	resp.Language = frontendLanguage
150→	caps := make([]string, len(CommandCapabilities))
151→	copy(caps, CommandCapabilities)
152→	caps = append(caps,
153→		"complex_type:date", "complex_type:duration", "complex_type:url",
154→		"complex_type:reg_exp", "complex_type:ip_address", "complex_type:big_int",
155→		"complex_type:rational", "complex_type:big_decimal", "complex_type:error",
156→	)
157→	resp.Capabilities = caps
158→	return resp
159→}
160→
161→func (h *Handler) handleAnalyze(resp Response, req Request) Response {
162→	if req.File == "" {
163→		resp.Status = "error"
164→		resp.Code = ErrInvalidRequest
165→		resp.Message = "analyze command requires a file path"
166→		return resp
167→	}
168→
169→	if _, err := os.Stat(req.File); err != nil {
170→		resp.Status = "error"
171→		resp.Code = ErrFileNotFound
172→		resp.Message = fmt.Sprintf("file not found: %s", req.File)
173→		return resp
174→	}
175→
176→	h.lastAnalyzedFile = req.File
177→
178→	var functionName string
179→	if req.Function != nil {
180→		functionName = *req.Function
181→	}
182→
183→	functions, err := AnalyzeFile(req.File, functionName)
184→	if err != nil {
185→		if functionName != "" && isNotFound(err) {
186→			resp.Status = "error"
187→			resp.Code = ErrFunctionNotFound
188→			resp.Message = fmt.Sprintf("function %q not found in %s", functionName, req.File)
189→			return resp
190→		}
191→		resp.Status = "error"
192→		resp.Code = ErrParseError
193→		resp.Message = err.Error()
194→		return resp
195→	}
196→
197→	resp.Status = "analyze"
198→	if functions == nil {
199→		functions = []FunctionAnalysis{}
200→	}
201→	resp.Functions = functions
202→	return resp
203→}
204→
205→func isNotFound(err error) bool {
206→	return err != nil && strings.HasPrefix(err.Error(), "function not found")
207→}
208→
209→func (h *Handler) handleInstrument(resp Response, req Request) Response {
210→	if req.File == "" {
211→		resp.Status = "error"
212→		resp.Code = ErrInvalidRequest
213→		resp.Message = "instrument command requires a file path"
214→		return resp
215→	}
216→
217→	if _, err := os.Stat(req.File); err != nil {
218→		resp.Status = "error"
219→		resp.Code = ErrFileNotFound
220→		resp.Message = fmt.Sprintf("file not found: %s", req.File)
221→		return resp
222→	}
223→
224→	h.lastAnalyzedFile = req.File
225→
226→	outputDir, err := instrument.InstrumentFile(req.File, req.Function, req.ProjectRoot)
227→	if err != nil {
228→		resp.Status = "error"
229→		resp.Code = ErrInternalError
230→		resp.Message = fmt.Sprintf("instrumentation failed: %v", err)
231→		return resp
232→	}
233→
234→	instrumented := true
235→	resp.Status = "instrument"
236→	resp.Instrumented = &instrumented
237→	resp.OutputFile = &outputDir
238→	return resp
239→}
240→
241→func (h *Handler) handleExecute(resp Response, req Request) Response {
242→	file := req.File
243→	if file == "" {
244→		file = h.lastAnalyzedFile
245→	}
246→	if file == "" {
247→		resp.Status = "error"
248→		resp.Code = ErrInvalidRequest
249→		resp.Message = "execute command requires a file path (or a prior analyze)"
250→		return resp
251→	}
252→
253→	if req.Function == nil || *req.Function == "" {
254→		resp.Status = "error"
255→		resp.Code = ErrInvalidRequest
256→		resp.Message = "execute command requires a function name"
257→		return resp
258→	}
259→
260→	if _, err := os.Stat(file); err != nil {
261→		resp.Status = "error"
262→		resp.Code = ErrFileNotFound
263→		resp.Message = fmt.Sprintf("file not found: %s", file)
264→		return resp
265→	}
266→
267→	// Convert protocol MockConfigs to instrument MockConfigs and pass to executor.
268→	var execMocks []instrument.MockConfig
269→	for _, m := range req.Mocks {
270→		execMocks = append(execMocks, instrument.MockConfig{
271→			Symbol:           m.Symbol,
272→			ReturnValues:     m.ReturnValues,
273→			ShouldTrackCalls: m.ShouldTrackCalls,
274→			DefaultBehavior:  m.DefaultBehavior,
275→		})
276→	}
277→	result, err := instrument.ExecuteFunction(file, *req.Function, req.Inputs, execMocks)
278→	if err != nil {
279→		resp.Status = "error"
280→		if strings.Contains(err.Error(), "function not found") {
281→			resp.Code = ErrFunctionNotFound
282→		} else if strings.Contains(err.Error(), "build failed") {
283→			resp.Code = ErrInstrumentationFailed
284→		} else if strings.Contains(err.Error(), "timed out") {
285→			resp.Code = ErrExecutionTimeout
286→		} else {
287→			resp.Code = ErrInternalError
288→		}
289→		resp.Message = err.Error()
290→		return resp
291→	}
292→
293→	resp.Status = "execute"
294→	resp.ReturnValue = result.ReturnValue
295→	resp.ThrownError = convertErrorInfo(result.ThrownError)
296→	resp.LinesExecuted = toIntSlice(result.LinesExecuted)
297→	resp.BranchPath = convertBranchPath(result.BranchPath)
298→	resp.PathConstraints = extractPathConstraints(result.BranchPath)
299→	resp.CallsToExternal = convertExternalCalls(result.ExternalCalls)
300→	resp.SideEffects = convertSideEffects(result.SideEffects)
301→	resp.ScopeEvents = result.ScopeEvents
302→	resp.Performance = &PerfMetrics{
303→		WallTimeMs:         result.Performance.WallTimeMs,
304→		CPUTimeUs:          result.Performance.CPUTimeUs,
305→		HeapUsedBytes:      result.Performance.HeapUsedBytes,
306→		HeapAllocatedBytes: result.Performance.HeapAllocatedBytes,
307→	}
308→
309→	return resp
310→}
311→
312→func convertErrorInfo(e *instrument.ErrorInfo) *ErrorInfo {
313→	if e == nil {
314→		return nil
315→	}
316→	var stack *string
317→	if e.Stack != "" {
318→		stack = &e.Stack
319→	}
320→	return &ErrorInfo{
321→		ErrorType: e.ErrorType,
322→		Message:   e.Message,
323→		Stack:     stack,
324→	}
325→}
326→
327→func toIntSlice(ints []int) []int {
328→	if ints == nil {
329→		return []int{}
330→	}
331→	return ints
332→}
333→
334→func convertBranchPath(branches []instrument.BranchDecision) []BranchDecision {
335→	result := make([]BranchDecision, len(branches))
336→	for i, b := range branches {
337→		constraint := &SymConstraint{Kind: "unknown", Hint: "no symbolic constraint from Go frontend"}
338→		if b.ConstraintJSON != "" {
339→			var sc SymConstraint
340→			if err := json.Unmarshal([]byte(b.ConstraintJSON), &sc); err == nil {
341→				constraint = &sc
342→			}
343→		}
344→		result[i] = BranchDecision{
345→			BranchID:   b.BranchID,
346→			Line:       b.Line,
347→			Taken:      b.Taken,
348→			Constraint: constraint,
349→		}
350→	}
351→	return result
352→}
353→
354→func extractPathConstraints(branches []instrument.BranchDecision) []SymConstraint {
355→	var constraints []SymConstraint
356→	for _, b := range branches {
357→		if b.ConstraintJSON == "" {
358→			continue
359→		}
360→		var sc SymConstraint
361→		if err := json.Unmarshal([]byte(b.ConstraintJSON), &sc); err == nil {
362→			constraints = append(constraints, sc)
363→		}
364→	}
365→	if constraints == nil {
366→		return []SymConstraint{}
367→	}
368→	return constraints
369→}
370→
371→// convertExternalCalls converts executor ExternalCall records to protocol format.
372→func convertExternalCalls(calls []instrument.ExternalCall) []ExternalCall {
373→	if len(calls) == 0 {
374→		return []ExternalCall{}
375→	}
376→	result := make([]ExternalCall, len(calls))
377→	for i, c := range calls {
378→		var args []any
379→		if c.Args != nil {
380→			json.Unmarshal(c.Args, &args) //nolint:errcheck
381→		}
382→		var retVal any
383→		if c.ReturnValue != nil {
384→			json.Unmarshal(c.ReturnValue, &retVal) //nolint:errcheck
385→		}
386→		result[i] = ExternalCall{
387→			Symbol:      c.Symbol,
388→			Args:        args,
389→			ReturnValue: retVal,
390→		}
391→	}
392→	return result
393→}
394→
395→// convertSideEffects converts executor SideEffects to protocol format.
396→func convertSideEffects(effects []instrument.SideEffect) []SideEffect {
397→	if len(effects) == 0 {
398→		return []SideEffect{}
399→	}
400→	result := make([]SideEffect, len(effects))
401→	for i, e := range effects {
402→		result[i] = SideEffect{
403→			Kind:    e.Kind,
404→			Level:   e.Level,
405→			Message: e.Message,
406→		}
407→	}
408→	return result
409→}
