  3→import (
  4→	"bufio"
  5→	"context"
  6→	"encoding/json"
  7→	"fmt"
  8→	"io"
  9→	"log/slog"
 10→	"os"
 11→	"strings"
 12→
 13→	"github.com/shatter-dev/shatter/shatter-go/generators"
